#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <stdint.h>

typedef struct Node {
    long long key;
    long long val;
    struct Node* next;
} Node;

#define MOD 1000003 // size of hash table, a prime > N

static Node* table[MOD];

static unsigned int hash_idx(long long x) {
    unsigned long long y = (unsigned long long)(x ^ (x >> 32));
    return (unsigned int)(y % MOD);
}

static long long get(Node* head, long long key) {
    for (Node* p = head; p; p = p->next) if (p->key == key) return p->val;
    return 0;
}

static void inc(Node** head, long long key) {
    for (Node* p = *head; p; p = p->next) if (p->key == key) { p->val++; return; }
    Node* nd = (Node*)malloc(sizeof(Node));
    nd->key = key; nd->val = 1; nd->next = *head; *head = nd;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long K; scanf("%d %lld", &N, &K);
        char s[100005]; scanf("%s", s);
        long long total = 0;
        for(char ch='a'; ch<='z'; ++ch){
            // clear hash table
            for(int i=0;i<MOD;++i){
                Node* p = table[i];
                while(p){ Node* nxt = p->next; free(p); p = nxt; }
                table[i]=NULL;
            }
            long long pref = 0;
            // i = 0 (empty prefix)
            inc(table + hash_idx(0), 0); // value[0] = 0
            for(int i=1;i<=N;++i){
                if(s[i-1]==ch) pref++;
                long long v = 2*pref - i;
                long long need = v - K;
                total += get(table[hash_idx(need)], need);
                inc(table + hash_idx(v), v);
            }
        }
        printf("%lld\n", total);
    }
    return 0;
}

