import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long K = fs.nextLong();
            char[] s = fs.next().toCharArray();
            long ans = 0;
            for (char ch = 'a'; ch <= 'z'; ++ch) {
                Long2LongMap cnt = new Long2LongHashMap();
                cnt.add(0L, 1L); // value[0]
                long pref = 0;
                for (int i = 1; i <= N; ++i) {
                    if (s[i - 1] == ch) pref++;
                    long v = 2L * pref - i;
                    ans += cnt.get(v - K);
                    cnt.add(v, 1L);
                }
            }
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }

    // Simple long->long hash map with open addressing (no deletions needed)
    static class Long2LongHashMap {
        private static final int INIT_CAP = 1 << 20; // enough for N<=1e5
        private long[] keys;
        private long[] vals;
        private boolean[] used;
        private int mask;
        Long2LongHashMap() {
            int cap = 1;
            while (cap < INIT_CAP) cap <<= 1;
            keys = new long[cap];
            vals = new long[cap];
            used = new boolean[cap];
            mask = cap - 1;
        }
        private int idx(long k) {
            long h = k ^ (k >>> 32);
            return (int)h & mask;
        }
        long get(long k) {
            int i = idx(k);
            while (used[i]) {
                if (keys[i] == k) return vals[i];
                i = (i + 1) & mask;
            }
            return 0L;
        }
        void add(long k, long delta) {
            int i = idx(k);
            while (used[i]) {
                if (keys[i] == k) { vals[i] += delta; return; }
                i = (i + 1) & mask;
            }
            used[i] = true;
            keys[i] = k;
            vals[i] = delta;
        }
    }

    // Fast scanner for Java
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char)c);
                c = readByte();
            }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        long nextLong() throws IOException { return Long.parseLong(next()); }
    }
}

