const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const K = Number(input[idx++]);
  const s = input[idx++];
  let ans = 0n;
  for (let code = 97; code <= 122; ++code) { // 'a'..'z'
    const ch = String.fromCharCode(code);
    const cnt = new Map();
    cnt.set(0, 1n); // value[0]
    let pref = 0;
    for (let i = 1; i <= N; ++i) {
      if (s[i-1] === ch) pref++;
      const v = 2*pref - i;
      const need = v - K;
      const prev = cnt.get(need) || 0n;
      ans += prev;
      cnt.set(v, (cnt.get(v) || 0n) + 1n);
    }
  }
  outputs.push(ans.toString());
}
